INSERT OR IGNORE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('Turion SW', '渔轮', '纺车式', 'Turion SW', 'Turion SW 8000', 'Turion SW是由REEF公司生产的一系列强大的海钓专用纺车式卷线轮。与该公司的所有渔线轮一样，Turion SW系列以卓越的制造工艺而著称。其渔线轮机身采用铝合金制造，拥有双重海水防护系统，能够有效地抵御海水侵蚀。Turion SW的机构性能卓越，极为可靠。这些渔线轮能够满足最高的需求，甚至能够轻松处理非常庞大的猎物。', '5.6:1', 0, '', '1.05', 0, '8000', '纺车式', '30.8kg', 0, '', '12g', 0, '30', '', '', '', '', 0, '157.37', '32500', '110.68kg', 0, '💧');
